async (params, browser) => {
  // Open spreadsheet
  await browser.open(`${params.spreadsheet_url}`)

  // Wait for spreadsheet grid to load
  await browser.waitForSelector('table.waffle, .waffle', 20000)

  // Let spreadsheet fully initialize
  await browser.wait(3000)

  // Navigate to the target cell using Name Box
  const navigate_to_cell = await browser.evaluate(`const nameBox = document.querySelector('#t-name-box input, input[aria-label="Name Box"], input.jfk-textinput'); if (!nameBox) return { error: 'Could not find Name Box input' }; nameBox.focus(); nameBox.click(); await new Promise(r => setTimeout(r, 500)); nameBox.select(); document.execCommand('insertText', false, params.cell); await new Promise(r => setTimeout(r, 300)); nameBox.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); await new Promise(r => setTimeout(r, 1000)); return { navigated: true, cell: params.cell }`)

  // Brief pause before typing
  await browser.wait(500)

  // Type value into the cell and confirm with Enter
  const write_result = await browser.evaluate(`const cellInput = document.querySelector('.cell-input[contenteditable="true"], [id="cell-editor"] [contenteditable="true"], .cell-input, .formulabar-input [contenteditable="true"]'); if (cellInput) { cellInput.focus(); await new Promise(r => setTimeout(r, 300)); document.execCommand('selectAll', false, null); document.execCommand('insertText', false, params.value); await new Promise(r => setTimeout(r, 500)); cellInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); } else { const waffle = document.querySelector('table.waffle'); const target = waffle || document.activeElement || document; target.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); await new Promise(r => setTimeout(r, 300)); document.execCommand('insertText', false, params.value); await new Promise(r => setTimeout(r, 500)); const active = document.activeElement || target; active.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); } await new Promise(r => setTimeout(r, 1000)); return { success: true, cell: params.cell, value: params.value, url: window.location.href }`)

  return write_result
}
